```javascript
const mongoose = require('mongoose');
const GameState = require('./models/gameState');
const Player = require('./models/player');

// Set up the database connection
mongoose.connect('mongodb://localhost/hearts-game', {
  useNewUrlParser: true,
  useUnifiedTopology: true
})
.then(() => console.log('Connected to MongoDB!'))
.catch(err => console.error('Error connecting to MongoDB: ', err));

// Create the players and save them to the database
const player1 = new Player({
  name: 'Player 1',
  hand: ['2C', '3C', '4C', '5H', '6H', '7C', '8C', '9D', '10D', 'QD', 'AD', '2D', '3D'],
  trickHistory: [],
  points: 0
});

const player2 = new Player({
  name: 'Player 2',
  hand: ['2H', '3H', '4H', '5C', '6C', '7H', '8H', '9S', '10S', 'QS', 'AS', '2S', '3S'],
  trickHistory: [],
  points: 0
});

const player3 = new Player({
  name: 'Player 3',
  hand: ['2S', '3S', '4S', '5D', '6D', '7S', '8S', '9H', '10H', 'QH', 'AH', '2H', '3H'],
  trickHistory: [],
  points: 0
});

const player4 = new Player({
  name: 'Player 4',
  hand: ['2D', '3D', '4D', '5S', '6S', '7D', '8D', '9C', '10C', 'QC', 'AC', '2C', '3C'],
  trickHistory: [],
  points: 0
});

// Create a new game state and save it to the database
const gameState = new GameState({
  players: [
    { playerId: player1._id, score: 0 },
    { playerId: player2._id, score: 0 },
    { playerId: player3._id, score: 0 },
    { playerId: player4._id, score: 0 },
  ],
  currentTrick: { trickNum: 1, leadSuit: 'C', heartsBroken: false, cards: [] },
  cardsPlayed: [],
  round: 1
});

Promise.all([player1.save(), player2.save(), player3.save(), player4.save(), gameState.save()])
.then(() => console.log('Players and game state created and saved!'))
.catch(err => console.error('Error creating/saving players and game state: ', err));

// Simulate a round of the game
for (let i = 0; i < 13; i++) {
  // Play a card for each player
  for (let j = 0; j < gameState.players.length; j++) {
    const player = await Player.findById(gameState.players[j].playerId);
    const playedCardIndex = Math.floor(Math.random() * player.hand.length);
    const playedCard = player.hand.splice(playedCardIndex, 1);
    gameState.currentTrick.cards.push(playedCard);
    gameState.cardsPlayed.push(playedCard);

    // Update the game state in the database to reflect the played card
    const updatedGameState = await GameState.findOneAndUpdate(
      { _id: gameState._id },
      { $set: { currentTrick: gameState.currentTrick, cardsPlayed: gameState.cardsPlayed } },
      { new: true }
    );
  }

  // Determine the winning card and update the game state
  const winningCard = gameState.currentTrick.cards.reduce((a, b) => (a.value > b.value) ? a : b);
  const winningPlayerIndex = gameState.currentTrick.cards.findIndex(card => card === winningCard);
  gameState.players[winningPlayerIndex].score += gameState.currentTrick.cards.reduce((a, b) => a.value = b.value);
  gameState.currentTrick = { trickNum: gameState.currentTrick.trickNum + 1, leadSuit: null, heartsBroken: false, cards: [] };

  // Update the game state in the database to reflect the end of the trick
  const updatedGameState = await GameState.findOneAndUpdate(
    { _id: gameState._id },
    { $set: { players: gameState.players, currentTrick: gameState.currentTrick } },
    { new: true }
  );
}

// Log the final scores for each player
const finalGameState = await GameState.findOne({ _id: gameState._id }).populate('players.playerId');
console.log(`Final scores for round ${finalGameState.round}:`);
finalGameState.players.forEach(playerObj => {
  console.log(`${playerObj.playerId.name}: ${playerObj.score}`);
});
```

This example simulates a single round of Hearts. The game state is created and saved to the database, along with each player's hand. Cards are then played randomly by each player, and the game state is updated in the database after each trick. After 13 tricks, the final scores are logged to the console.

